class Solution:
    def stoneGameV(self, stoneValue):
        n = len(stoneValue)

        def solve(i, j):
            if i == j:
                return 0
            total = sum(stoneValue[i:j + 1])
            best = 0
            left = 0
            for k in range(i, j):
                left += stoneValue[k]
                right = total - left
                if left < right:
                    cand = left + solve(i, k)
                elif left > right:
                    cand = right + solve(k + 1, j)
                else:
                    cand = left + max(solve(i, k), solve(k + 1, j))
                if cand > best:
                    best = cand
            return best

        return solve(0, n - 1)

