import sys
from functools import lru_cache

class Solution:
    def stoneGameV(self, stoneValue):
        sys.setrecursionlimit(10000)
        n = len(stoneValue)
        prefix = [0] * (n + 1)
        for idx, v in enumerate(stoneValue):
            prefix[idx + 1] = prefix[idx] + v

        @lru_cache(maxsize=None)
        def best(i, j):
            if i == j:
                return 0
            total = prefix[j + 1] - prefix[i]
            left = 0
            top = 0
            for k in range(i, j):
                left += stoneValue[k]
                right = total - left
                if left < right:
                    cand = left + best(i, k)
                elif left > right:
                    cand = right + best(k + 1, j)
                else:
                    cand = left + max(best(i, k), best(k + 1, j))
                if cand > top:
                    top = cand
            return top

        result = best(0, n - 1)
        best.cache_clear()
        return result

