var stoneGameV = function(stoneValue) {
    const n = stoneValue.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + stoneValue[i];
    const dp = Array.from({ length: n }, () => new Array(n).fill(-1));
    const best = (i, j) => {
        if (i === j) return 0;
        if (dp[i][j] !== -1) return dp[i][j];
        const total = prefix[j + 1] - prefix[i];
        let left = 0;
        let top = 0;
        for (let k = i; k < j; k++) {
            left += stoneValue[k];
            const right = total - left;
            let cand;
            if (left < right) cand = left + best(i, k);
            else if (left > right) cand = right + best(k + 1, j);
            else cand = left + Math.max(best(i, k), best(k + 1, j));
            if (cand > top) top = cand;
        }
        dp[i][j] = top;
        return top;
    };
    return best(0, n - 1);
};
